import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import axios from 'axios';

function Register() {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [error, setError] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    
    if (password !== confirmPassword) {
      setError('Passwords do not match');
      return;
    }
    
    if (password.length < 6) {
      setError('Password must be at least 6 characters long');
      return;
    }
    
    setIsLoading(true);
    
    try {
      await axios.post('/register', { email, password });
      navigate('/login');
    } catch (err) {
      setError('Failed to register. Email might already be in use.');
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="container fade-in">
      <div className="auth-header">
        <h2>Create Account</h2>
        <p style={{textAlign: 'center', color: 'var(--gray)', marginBottom: '30px'}}>
          Join us to start managing your members
        </p>
      </div>
      
      {error && <div className="error slide-in">{error}</div>}
      
      <form onSubmit={handleSubmit}>
        <div className="form-group">
          <input
            type="email"
            placeholder="Email address"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            required
            className="fade-in"
            style={{animationDelay: '0.1s'}}
          />
        </div>
        
        <div className="form-group">
          <input
            type="password"
            placeholder="Password"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            required
            minLength="6"
            className="fade-in"
            style={{animationDelay: '0.2s'}}
          />
        </div>
        
        <div className="form-group">
          <input
            type="password"
            placeholder="Confirm Password"
            value={confirmPassword}
            onChange={(e) => setConfirmPassword(e.target.value)}
            required
            minLength="6"
            className="fade-in"
            style={{animationDelay: '0.3s'}}
          />
        </div>
        
        <button 
          type="submit" 
          className="btn btn-primary fade-in"
          style={{animationDelay: '0.4s'}}
          disabled={isLoading}
        >
          {isLoading ? 'Creating Account...' : 'Create Account'}
        </button>
      </form>
      
      <div className="auth-links fade-in" style={{animationDelay: '0.5s'}}>
        <p>Already have an account? <Link to="/login" className="link">Sign in here</Link></p>
      </div>
    </div>
  );
}

export default Register;
